// Generate domain check list
const domains = [
  'os.smarterbot.store',
  'os.smarterbot.cl',
  'bolt.smarterbot.store',
  'bolt.smarterbot.cl',
  'docling.smarterbot.store',
  'bookish.smarterbot.store',
  'emdash.smarterbot.store',
  'food.smarterbot.cl',
  'docs.smarterbot.cl',
  'n8n.smarterbot.store',
  'api.smarterbot.store',
  'ecu.smarterbot.store'
];

return domains.map(domain => ({
  json: {
    domain,
    url: `https://${domain}`,
    check_ts: Math.floor(Date.now() / 1000),
    check_id: `chk_${Date.now()}_${domain.replace(/[^a-z]/g, '')}`
  }
}));

const results = [];

for (const item of $input.all()) {
  const domain = item.json.domain;
  const checkId = item.json.check_id;
  const ts = item.json.check_ts;

  // HTTP result
  const httpResult = item.json.httpResult;
  const httpStatus = httpResult?.status || 0;
  const responseTime = httpResult?.timing?.total || 0;

  // SSL result  
  const sslResult = item.json.sslResult;
  const sslGrade = sslResult?.endpoints?.[0]?.grade || 'N/A';
  const sslExpiry = sslResult?.certs?.[0]?.notAfter || '';

  // Calculate days remaining
  let daysRemaining = 0;
  if (sslExpiry) {
    const expiryDate = new Date(sslExpiry);
    const now = new Date();
    daysRemaining = Math.max(0, Math.floor((expiryDate - now) / (1000 * 60 * 60 * 24)));
  }

  // Determine health status
  let healthStatus = 'healthy';
  let severity = 'info';

  if (httpStatus === 0) {
    healthStatus = 'down';
    severity = 'critical';
  } else if (httpStatus >= 500) {
    healthStatus = 'error';
    severity = 'critical';
  } else if (httpStatus >= 400) {
    healthStatus = 'warning';
    severity = 'warning';
  } else if (daysRemaining < 30) {
    healthStatus = 'ssl_expiring';
    severity = 'warning';
  } else if (daysRemaining < 7) {
    healthStatus = 'ssl_critical';
    severity = 'critical';
  } else if (['F', 'T'].includes(sslGrade)) {
    healthStatus = 'ssl_weak';
    severity = 'warning';
  }

  results.push({
    json: {
      ts,
      domain,
      http_status: httpStatus,
      ssl_grade: sslGrade,
      ssl_expiry: sslExpiry,
      ssl_days_remaining: daysRemaining,
      response_time_ms: responseTime,
      health_status: healthStatus,
      error: httpResult?.error || null,
      check_id: checkId,
      severity,
      // For BI metrics
      bi_metric: true,
      metric_name: 'domain_health',
      metric_value: healthStatus === 'healthy' ? 1 : 0,
      tags: JSON.stringify({ domain, severity, ssl_grade })
    }
  });
}

return results;

